blocks.body:
{
    "level": "A1–A2",
    "intro": "W tym temacie poznasz <strong>trzy rodzaje użycia przedimka</strong> w języku angielskim: <strong>a</strong>, <strong>an</strong> i <strong>the</strong>, a także sytuacje, w których nie używamy przedimka wcale.",
    "rules": [
        {
            "label": "A / An",
            "color": "emerald",
            "text": "<strong>Przedimek nieokreślony</strong> używamy, gdy coś pojawia się po raz pierwszy albo nie jest jeszcze sprecyzowane:",
            "example": "I saw a dog. / She is an engineer."
        },
        {
            "label": "The",
            "color": "blue",
            "text": "<strong>Przedimek określony</strong> używamy, gdy mówimy o czymś konkretnym lub już znanym rozmówcy:",
            "example": "The dog was big. / The sun is bright."
        },
        {
            "label": "Zero (Ø)",
            "color": "amber",
            "text": "<strong>Brak przedimka</strong> pojawia się przy znaczeniu ogólnym, pojęciach abstrakcyjnych i liczbie mnogiej użytej ogólnie:",
            "example": "I love music. / Dogs are loyal."
        }
    ]
}

{
    "title": "1. Trzy sposoby użycia przedimka",
    "intro": "W angielskim spotkasz trzy podstawowe warianty:",
    "items": [
        {
            "label": "A / An",
            "title": "Nieokreślony",
            "subtitle": "Mówimy o czymś nowym, ogólnym albo o jednym przedstawicielu grupy: a book, an apple"
        },
        {
            "label": "The",
            "title": "Określony",
            "subtitle": "Mówimy o czymś konkretnym, już znanym lub jedynym w swoim rodzaju: the book I bought"
        },
        {
            "label": "Zero Ø",
            "title": "Bez przedimka",
            "subtitle": "Znaczenie ogólne, pojęcia abstrakcyjne i liczba mnoga użyta ogólnie: I love music"
        }
    ]
}

{
    "title": "2. A czy an?",
    "sections": [
        {
            "label": "A przed spółgłoską w wymowie",
            "color": "emerald",
            "description": "Używamy <strong>a</strong> przed słowami, które <strong>zaczynają się od spółgłoski w wymowie</strong>.",
            "examples": [
                {
                    "en": "a book, a car, a dog",
                    "ua": "książka, samochód, pies"
                },
                {
                    "en": "a university [juːnɪˈvɜːsɪti]",
                    "ua": "uniwersytet (na początku słychać [j])"
                },
                {
                    "en": "a European country",
                    "ua": "europejski kraj (na początku słychać [j])"
                },
                {
                    "en": "a one-way street",
                    "ua": "ulica jednokierunkowa (na początku słychać [w])"
                }
            ]
        },
        {
            "label": "An przed samogłoską w wymowie",
            "color": "sky",
            "description": "Używamy <strong>an</strong> przed słowami, które <strong>zaczynają się od samogłoski w wymowie</strong>.",
            "examples": [
                {
                    "en": "an apple, an egg, an idea",
                    "ua": "jabłko, jajko, pomysł"
                },
                {
                    "en": "an hour [aʊə]",
                    "ua": "godzina (h jest nieme)"
                },
                {
                    "en": "an honest person",
                    "ua": "uczciwa osoba (h jest nieme)"
                },
                {
                    "en": "an MBA degree",
                    "ua": "dyplom MBA (na początku słychać [e])"
                }
            ]
        },
        {
            "label": "Liczy się wymowa",
            "color": "amber",
            "description": "Wybór <strong>a / an</strong> zależy od <strong>dźwięku</strong>, a nie od pierwszej litery w zapisie.",
            "examples": [
                {
                    "en": "a uniform (sound [j])",
                    "ua": "uniform, bo na początku słychać [j]"
                },
                {
                    "en": "an umbrella (sound [ʌ])",
                    "ua": "umbrella, bo na początku słychać samogłoskę"
                }
            ],
            "note": "Najpierw pomyśl, jak dane słowo brzmi, a dopiero potem wybierz przedimek."
        }
    ]
}

{
    "title": "3. Kiedy używamy a / an",
    "sections": [
        {
            "label": "Pierwsza wzmianka",
            "color": "emerald",
            "description": "Używamy <strong>a / an</strong>, gdy wspominamy o czymś <strong>po raz pierwszy</strong> albo nie mówimy dokładnie, o co chodzi.",
            "examples": [
                {
                    "en": "I saw a cat in the garden.",
                    "ua": "Widziałem w ogrodzie kota."
                },
                {
                    "en": "She bought a new dress.",
                    "ua": "Kupiła nową sukienkę."
                },
                {
                    "en": "There is a problem.",
                    "ua": "Jest pewien problem."
                }
            ]
        },
        {
            "label": "Zawody i role",
            "color": "sky",
            "description": "Przedimek <strong>a / an</strong> pojawia się też przy <strong>zawodach, rolach i funkcjach</strong>.",
            "examples": [
                {
                    "en": "She is a doctor.",
                    "ua": "Ona jest lekarką."
                },
                {
                    "en": "He is an engineer.",
                    "ua": "On jest inżynierem."
                },
                {
                    "en": "I'm a student.",
                    "ua": "Jestem studentem."
                }
            ]
        },
        {
            "label": "Jeden z wielu",
            "color": "amber",
            "description": "Używamy <strong>a / an</strong>, gdy mamy na myśli <strong>jeden egzemplarz</strong> z większej grupy.",
            "examples": [
                {
                    "en": "A dog is a loyal animal.",
                    "ua": "Pies to wierne zwierzę."
                },
                {
                    "en": "I need a pen.",
                    "ua": "Potrzebuję długopisu."
                }
            ],
            "note": "A / an często można rozumieć jako „jeden”, „jakiś” albo „dowolny”."
        }
    ]
}

{
    "title": "4. Kiedy używamy the",
    "sections": [
        {
            "label": "Coś już znanego",
            "color": "blue",
            "description": "Używamy <strong>the</strong>, gdy rozmówca wie już, o czym mówimy, albo gdy dana rzecz została wcześniej wspomniana.",
            "examples": [
                {
                    "en": "I saw a cat. The cat was black.",
                    "ua": "Widziałem kota. Ten kot był czarny."
                },
                {
                    "en": "Where is the bathroom?",
                    "ua": "Gdzie jest łazienka?"
                },
                {
                    "en": "Did you read the book I gave you?",
                    "ua": "Czy przeczytałeś książkę, którą ci dałem?"
                }
            ]
        },
        {
            "label": "Rzeczy jedyne w swoim rodzaju",
            "color": "sky",
            "description": "Używamy <strong>the</strong>, gdy chodzi o coś <strong>jedynego</strong> albo wyjątkowego.",
            "examples": [
                {
                    "en": "the sun, the moon, the Earth",
                    "ua": "słońce, księżyc, Ziemia"
                },
                {
                    "en": "the Internet, the radio",
                    "ua": "internet, radio"
                },
                {
                    "en": "the President of Ukraine",
                    "ua": "prezydent Ukrainy"
                }
            ]
        },
        {
            "label": "Dodatkowe doprecyzowanie",
            "color": "purple",
            "description": "Używamy <strong>the</strong>, gdy rzeczownik jest <strong>dookreślony</strong> przez dodatkową informację.",
            "examples": [
                {
                    "en": "the capital of France",
                    "ua": "stolica Francji"
                },
                {
                    "en": "the man in the red jacket",
                    "ua": "mężczyzna w czerwonej kurtce"
                },
                {
                    "en": "the book that you recommended",
                    "ua": "książka, którą poleciłeś"
                }
            ]
        },
        {
            "label": "Niektóre nazwy geograficzne",
            "color": "amber",
            "description": "Przedimek <strong>the</strong> występuje z częścią nazw geograficznych i nazw państw złożonych.",
            "examples": [
                {
                    "en": "the USA, the UK, the Netherlands",
                    "ua": "USA, Wielka Brytania, Niderlandy"
                },
                {
                    "en": "the Pacific Ocean, the Dnipro",
                    "ua": "Ocean Spokojny, Dniepr"
                },
                {
                    "en": "the Alps, the Carpathians",
                    "ua": "Alpy, Karpaty"
                }
            ],
            "note": "The sugeruje: „ta konkretna rzecz, o której wiemy”."
        }
    ]
}

{
    "title": "5. Kiedy nie używamy przedimka",
    "sections": [
        {
            "label": "Znaczenie ogólne",
            "color": "amber",
            "description": "Gdy mówimy o czymś <strong>ogólnie</strong> albo o pojęciu abstrakcyjnym, przedimek zwykle nie jest potrzebny.",
            "examples": [
                {
                    "en": "I love music.",
                    "ua": "Lubię muzykę."
                },
                {
                    "en": "Life is beautiful.",
                    "ua": "Życie jest piękne."
                },
                {
                    "en": "Money is not everything.",
                    "ua": "Pieniądze to nie wszystko."
                }
            ]
        },
        {
            "label": "Liczba mnoga w znaczeniu ogólnym",
            "color": "sky",
            "description": "Brak przedimka jest też typowy, gdy mówimy o całej klasie rzeczy w <strong>liczbie mnogiej</strong>.",
            "examples": [
                {
                    "en": "Dogs are loyal animals.",
                    "ua": "Psy są wiernymi zwierzętami."
                },
                {
                    "en": "I like cats.",
                    "ua": "Lubię koty."
                },
                {
                    "en": "Books are expensive.",
                    "ua": "Książki są drogie."
                }
            ]
        },
        {
            "label": "Większość nazw własnych",
            "color": "emerald",
            "description": "Większość <strong>krajów, miast, imion i nazw własnych</strong> występuje bez przedimka.",
            "examples": [
                {
                    "en": "Ukraine, Kyiv, London",
                    "ua": "Ukraina, Kijów, Londyn"
                },
                {
                    "en": "Mount Everest, Lake Baikal",
                    "ua": "Mount Everest, jezioro Bajkał"
                },
                {
                    "en": "John, Maria",
                    "ua": "John, Maria"
                }
            ]
        },
        {
            "label": "Stałe wyrażenia",
            "color": "purple",
            "description": "W wielu <strong>utartych połączeniach</strong> przedimek po prostu się nie pojawia.",
            "examples": [
                {
                    "en": "at home, at work, at school",
                    "ua": "w domu, w pracy, w szkole"
                },
                {
                    "en": "by bus, by car, by plane",
                    "ua": "autobusem, samochodem, samolotem"
                },
                {
                    "en": "go to bed, have breakfast",
                    "ua": "iść spać, zjeść śniadanie"
                }
            ]
        }
    ]
}

{
    "title": "6. Szybkie porównanie",
    "intro": "Najważniejsze zastosowania przedimków w jednym miejscu:",
    "rows": [
        {
            "en": "First mention",
            "ua": "Pierwsza wzmianka",
            "note": "A / an: I saw a dog."
        },
        {
            "en": "Known / mentioned",
            "ua": "Coś już znanego",
            "note": "The: The dog was big."
        },
        {
            "en": "Unique things",
            "ua": "Rzeczy jedyne w swoim rodzaju",
            "note": "The: the sun, the moon"
        },
        {
            "en": "Professions",
            "ua": "Zawody i role",
            "note": "A / an: She is a teacher."
        },
        {
            "en": "General / abstract",
            "ua": "Znaczenie ogólne / abstrakcyjne",
            "note": "Ø: I love music."
        },
        {
            "en": "Plural in general",
            "ua": "Liczba mnoga w znaczeniu ogólnym",
            "note": "Ø: Dogs are loyal."
        }
    ],
    "warning": "A / an wprowadza coś nowego lub niesprecyzowanego. The wskazuje na coś konkretnego. Ø oznacza sens ogólny."
}

{
    "title": "7. Kilka szczególnych przypadków",
    "sections": [
        {
            "label": "The + adjective = grupa ludzi",
            "color": "purple",
            "description": "Połączenie <strong>the + adjective</strong> może oznaczać całą grupę ludzi.",
            "examples": [
                {
                    "en": "the rich, the poor",
                    "ua": "bogaci, biedni"
                },
                {
                    "en": "the young, the elderly",
                    "ua": "młodzi, osoby starsze"
                },
                {
                    "en": "the unemployed",
                    "ua": "bezrobotni"
                }
            ]
        },
        {
            "label": "Instrumenty muzyczne",
            "color": "sky",
            "description": "Przy nazwach instrumentów zwykle używamy <strong>the</strong>.",
            "examples": [
                {
                    "en": "play the piano",
                    "ua": "grać na pianinie"
                },
                {
                    "en": "play the guitar",
                    "ua": "grać na gitarze"
                },
                {
                    "en": "play the violin",
                    "ua": "grać na skrzypcach"
                }
            ]
        },
        {
            "label": "Pory dnia",
            "color": "amber",
            "description": "Mówimy <strong>in the morning / afternoon / evening</strong>, ale <strong>at night</strong> bez the.",
            "examples": [
                {
                    "en": "in the morning",
                    "ua": "rano"
                },
                {
                    "en": "in the afternoon",
                    "ua": "po południu"
                },
                {
                    "en": "at night",
                    "ua": "w nocy"
                }
            ]
        }
    ]
}

{
    "title": "8. Typowe błędy",
    "items": [
        {
            "label": "Błąd 1",
            "color": "rose",
            "title": "Brak przedimka przy zawodzie.",
            "wrong": "She is doctor.",
            "right": "✅ <span class=\"font-mono\">She is a doctor.<\/span>"
        },
        {
            "label": "Błąd 2",
            "color": "amber",
            "title": "A zamiast an przed samogłoską w wymowie.",
            "wrong": "a hour, a honest person",
            "right": "✅ <span class=\"font-mono\">an hour, an honest person<\/span>"
        },
        {
            "label": "Błąd 3",
            "color": "sky",
            "title": "The przy pojęciach abstrakcyjnych użytych ogólnie.",
            "wrong": "The life is beautiful.",
            "right": "✅ <span class=\"font-mono\">Life is beautiful.<\/span>"
        },
        {
            "label": "Błąd 4",
            "color": "purple",
            "title": "The przed większością nazw krajów.",
            "wrong": "I live in the Ukraine.",
            "right": "✅ <span class=\"font-mono\">I live in Ukraine.<\/span>"
        }
    ]
}

{
    "title": "10. Ćwiczenia",
    "select_title": "Ćwiczenie 1. Wybierz poprawny przedimek",
    "select_intro": "Wstaw a, an, the albo Ø (bez przedimka).",
    "selects": [
        {
            "label": "She is ___ engineer. (a / an / the / Ø)",
            "prompt": "Który przedimek pasuje?"
        },
        {
            "label": "I saw ___ sun today. (a / an / the / Ø)",
            "prompt": "Który przedimek pasuje?"
        },
        {
            "label": "___ dogs are loyal animals. (a / an / the / Ø)",
            "prompt": "Który przedimek pasuje?"
        },
        {
            "label": "I need ___ hour to finish. (a / an / the / Ø)",
            "prompt": "Który przedimek pasuje?"
        }
    ],
    "options": [
        "a",
        "an",
        "the",
        "Ø"
    ],
    "input_title": "Ćwiczenie 2. Wpisz a albo an",
    "input_intro": "Uzupełnij wyrażenia odpowiednim przedimkiem.",
    "inputs": [
        {
            "before": "___ university",
            "after": "→"
        },
        {
            "before": "___ honest answer",
            "after": "→"
        },
        {
            "before": "___ European country",
            "after": "→"
        }
    ],
    "rephrase_title": "Ćwiczenie 3. Popraw błąd",
    "rephrase_intro": "Znajdź i popraw błąd związany z przedimkiem.",
    "rephrase": [
        {
            "example_label": "Przykład:",
            "example_original": "He is teacher.",
            "example_target": "He is a teacher."
        },
        {
            "original": "1. I love the music.",
            "placeholder": "Popraw zdanie"
        },
        {
            "original": "2. She lives in the France.",
            "placeholder": "Popraw zdanie"
        }
    ]
}

{
    "title": "Kontynuuj naukę",
    "items": [
        {
            "label": "Articles",
            "current": true
        },
        {
            "label": "Countable vs Uncountable",
            "current": false
        },
        {
            "label": "Some / Any",
            "current": false
        },
        {
            "label": "Quantifiers",
            "current": false
        }
    ]
}
